/**
 * Tavily API firewall config generator.
 *
 * Data source: https://docs.tavily.com/documentation/api-reference/introduction
 *
 * Tavily uses Bearer token authentication.
 * API key format: tvly- prefix + alphanumeric chars.
 */

import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://docs.tavily.com/documentation/api-reference/introduction";
// Format: tvly- prefix + alphanumeric; exact length not documented
const PLACEHOLDER_VALUE = "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";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Tavily API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:tavily",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const tavilyFirewall = {",
    '  name: "tavily",',
    '  description: "Tavily API",',
    "  placeholders: {",
    `    TAVILY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.tavily.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.TAVILY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Tavily firewall config...");
  const ts = generateTypeScript();
  writeOutput("tavily", ts, import.meta.dirname);
}
